package com.cognizant.springtesting; import static org.junit.jupiter.api.Assertions.*; import static org.mockito.Mockito.*; import java.util.*; import org.junit.jupiter.api.Test; public class UserServiceTest {@Test void testMissingUser(){UserRepository repository=mock(UserRepository.class);when(repository.findById(99L)).thenReturn(Optional.empty());NoSuchElementException exception=assertThrows(NoSuchElementException.class,()->new UserService(repository).getUserById(99L));assertEquals("User not found",exception.getMessage());verify(repository).findById(99L);}}
